import React from 'react';
import './common.scss';

type Props = {
	fullScreen: boolean;
};

export default function LoadingIcon({ fullScreen }: Props) {
	const loadingClass = fullScreen ? 'fullscreen' : '';
	return (
		<div className={loadingClass}>
			<i className="pi icon--search pi-spin" />
		</div>
	);
}
